/*
 * Type utils.
 */
export const isInternalV = (entry) => 'children' in entry;
export const isInternal = (entry) => 'children' in entry;
export const toLeaf = (entry) => {
    const typedEntry = entry;
    delete typedEntry.children;
    delete typedEntry.showChildren;
    return typedEntry;
};
export const toInternal = (entry, showChildren) => {
    const typedEntry = entry;
    typedEntry.children = [];
    typedEntry.showChildren = showChildren;
    return typedEntry;
};
